        self.index = try container.decodeIfPresent(UInt.self, forKey: .index) ?? 0
        self.url = try container.decodeIfPresent(String.self, forKey: .url) ?? ""
        self.text = try container.decodeIfPresent(String.self, forKey: .text) ?? ""
