/// Errors that can occur during crawling, scraping, or mapping operations.
public enum CrawlError: Swift.Error {
    /// The requested page was not found (HTTP 404).
    case notFound(message: String, field0: String)
    /// The request was unauthorized (HTTP 401).
    case unauthorized(message: String, field0: String)
    /// The request was forbidden (HTTP 403).
    case forbidden(message: String, field0: String)
    /// The request was blocked by a WAF or bot protection (HTTP 403 with WAF indicators).
    ///
    /// `vendor` is the lowercase identifier of the detected WAF (e.g. "cloudflare",
    /// "datadome"). When the engine cannot identify the vendor, it uses "unknown".
    /// `message` is the freeform description for logs and human readers.
    ///
    /// The stable error tag remains `forbidden: waf/blocked: MESSAGE` so existing
    /// log-grep patterns and cross-language bindings continue to work; vendor is
    /// surfaced separately for structured consumers.
    case wafBlocked(vendor: String, message: String)
    /// The request timed out.
    case timeout(message: String, field0: String)
    /// The request was rate-limited (HTTP 429).
    case rateLimited(message: String, field0: String)
    /// A server error occurred (HTTP 5xx).
    case serverError(message: String, field0: String)
    /// A bad gateway error occurred (HTTP 502).
    case badGateway(message: String, field0: String)
    /// The resource is permanently gone (HTTP 410).
    case gone(message: String, field0: String)
    /// A connection error occurred.
    case connection(message: String, field0: String)
    /// A DNS resolution error occurred.
    case dns(message: String, field0: String)
    /// An SSL/TLS error occurred.
    case ssl(message: String, field0: String)
    /// Data was lost or truncated during transfer.
    case dataLoss(message: String, field0: String)
    /// The browser failed to launch, connect, or navigate.
    case browserError(message: String, field0: String)
    /// The browser page load or rendering timed out.
    case browserTimeout(message: String, field0: String)
    /// The provided configuration is invalid.
    case invalidConfig(message: String, field0: String)
    /// The requested capability is not supported by the active backend or build.
    case unsupported(message: String, field0: String)
    /// A URL was rejected by SSRF policy (private IP, metadata, disallowed scheme, etc).
    case ssrfPolicyViolation(message: String, url: String, reason: String)
    /// An unclassified error occurred.
    case other(message: String, field0: String)
    /// Synthetic case raised when a Rust serde unit-enum raw value cannot
    /// be mapped to a known Swift case during DTO unmarshaling.
    case validation(message: String, source: String)
}

// MARK: - JSON-String Convenience Overloads
// These overloads accept JSON-encoded config parameters and decode them automatically.
// Enables e2e tests to pass JSON strings directly without typed config construction.

/// Resolves a string argument as either a file path or literal UTF-8 content.
/// Searches: current working directory, ALEF_TEST_DOCUMENTS_DIR env var,
/// and ancestor `test_documents/` or `fixtures/` directories (up to 16 levels).
/// If no file is found, treats the string as UTF-8 content and returns its bytes.
private func _loadBytesFromPathOrUtf8(_ pathOrContent: String) throws -> [UInt8] {
    let fm = FileManager.default
    var roots: [String] = [fm.currentDirectoryPath]
    if let envRoot = ProcessInfo.processInfo.environment["ALEF_TEST_DOCUMENTS_DIR"] {
        roots.append(envRoot)
    }
    var walker = URL(fileURLWithPath: fm.currentDirectoryPath)
    for _ in 0..<16 {
        roots.append(walker.appendingPathComponent("test_documents").path)
        roots.append(walker.appendingPathComponent("fixtures").path)
        let parent = walker.deletingLastPathComponent()
        if parent.path == walker.path { break }
        walker = parent
    }
    let candidates = [pathOrContent] + roots.map { ($0 as NSString).appendingPathComponent(pathOrContent) }
    for path in candidates {
        if fm.fileExists(atPath: path), let data = try? Data(contentsOf: URL(fileURLWithPath: path)) {
            return [UInt8](data)
        }
    }
    return [UInt8](pathOrContent.utf8)
}

